<template>
    <div>
      <el-card>
        <el-form label-width="100px" size="mini">
            <el-form-item label="原密码">
              <el-input show-password v-model="form.oldPassword"></el-input>
            </el-form-item>
            <el-form-item label="新密码">
              <el-input show-password v-model="form.password"></el-input>
            </el-form-item>
            <el-form-item label="确认密码">
              <el-input show-password v-model="form.confirm_password"></el-input>
            </el-form-item>

        </el-form>
        <el-form label-width="80px" size="mini">
            <div style="text-align: center;">
                <el-button type="primary" @click="submit">提交</el-button>
            </div>
        </el-form>
      </el-card>

      <el-card v-if="info['余额']">
        <p>操作：{{info['操作']}}</p>
        <p>转入姓名：{{info['转入姓名']}}</p>
        <p>转入账号：{{info['转入账号']}}</p>
        <p>余额：{{info['余额']}}元</p>
        
      </el-card>
        
    </div>
  </template>
  
  <script>
    import {
      userfunChange, // 修改密码
  } from '@/api/index'
  
    export default {
      data() {
        return {
          userInfo: {
            user: {},
          }, // 个人信息
          form: {},
          info: {}
        }
      },
      mounted(){
        this.userInfo = JSON.parse(window.localStorage.getItem('userInfo'))
      },
      methods: {
        // 修改密码
        async submit(){
            let page = {...this.form}
            if(!page.oldPassword){
                this.$message.warning('请输入原密码')
                return
            }
            if(page.oldPassword != this.userInfo.password){
                this.$message.warning('原密码不正确')
                return
            }
            if(!page.password){
                this.$message.warning('请输入新密码')
                return
            }
            if(page.password != page.confirm_password){
                this.$message.warning('新密码与确认密码不一致')
                return
            }
            let res = await userfunChange(page)
            console.log(res);
            if(res.indexOf('success') != -1){
                this.$message.success('修改密码成功')
                this.user.password = page.password
                window.localStorage.setItem('userInfo', JSON.stringify(this.user));
            }else {
                this.$message.warning(JSON.stringify(res))
            }
        },
      }
    }
  </script>
  
  <style scoped>

    /deep/.el-card{
      margin-top: 10px;
    }
  </style>
  
  


